# Icons that should be mirrored in RTL (directional icons)
DIRECTIONAL_ICONS = {
    "arrow-right",
    "arrow-left",
    "chevron-right",
    "chevron-left",
}


@register.simple_tag
def icon(name, size="5", css_class="", directional=False):
    """
    Render an inline SVG icon from the Heroicons set.

    Args:
        name: Icon name (e.g., "home", "user", "check")
        size: Tailwind size class number (default "5" = w-5 h-5)
        css_class: Additional CSS classes
        directional: If True, adds .icon-directional class (mirrors in RTL)

    Returns:
        Safe HTML string with the SVG element.

    Usage:
        {% icon "home" %}
        {% icon "arrow-right" size="6" css_class="text-primary" directional=True %}
    """
    path_data = ICON_PATHS.get(name)
    if not path_data:
        return mark_safe(f'<!-- icon "{name}" not found -->')

    # Auto-detect directional icons
    is_directional = directional or name in DIRECTIONAL_ICONS
    direction_class = "icon-directional" if is_directional else ""

    classes = f"w-{size} h-{size} {direction_class} {css_class}".strip()

    svg = (
        f'<svg class="{classes}" fill="none" stroke="currentColor" '
        f'viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" '
        f'aria-hidden="true">'
        f'<path stroke-linecap="round" stroke-linejoin="round" '
        f'stroke-width="1.5" d="{path_data}"/>'
        f"</svg>"
    )
    return mark_safe(svg)


@register.simple_tag
def icon_names():
    """Return all available icon names (for showcase/documentation)."""
    return sorted(ICON_PATHS.keys())
